using UnityEngine;
using System.Collections.Generic;
using System.Security.Cryptography;
using System.Text;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    public int damage = 10;
    
    private Dictionary<string, int> shopItems = new Dictionary<string, int>();
    private string secretKey = "your_secret_key_here";
    
    void Start()
    {
        InitializeShop();
    }
    
    void InitializeShop()
    {
        shopItems.Add("HealthPotion", 50);
        shopItems.Add("DamageUpgrade", 100);
        shopItems.Add("MaxHealthUpgrade", 150);
    }
    
    public void TakeDamage(int damageAmount)
    {
        health -= damageAmount;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(string item)
    {
        if (shopItems.ContainsKey(item))
        {
            return currency >= shopItems[item];
        }
        return false;
    }
    
    public void PurchaseItem(string item)
    {
        if (CanAfford(item))
        {
            currency -= shopItems[item];
            ApplyItemEffect(item);
        }
    }
    
    private void ApplyItemEffect(string item)
    {
        switch (item)
        {
            case "HealthPotion":
                health = Mathf.Min(maxHealth, health + 50);
                break;
            case "DamageUpgrade":
                damage += 5;
                break;
            case "MaxHealthUpgrade":
                maxHealth += 20;
                health = maxHealth;
                break;
        }
    }
    
    public string GenerateSecureToken(string data)
    {
        using (HMACSHA256 hmac = new HMACSHA256(Encoding.UTF8.GetBytes(secretKey)))
        {
            byte[] hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(data));
            return System.BitConverter.ToString(hash).Replace("-", "").ToLower();
        }
    }
    
    public bool VerifyToken(string data, string token)
    {
        string expectedToken = GenerateSecureToken(data);
        return token == expectedToken;
    }
    
    public int CalculateDamage(int baseDamage, int level)
    {
        return baseDamage + (level * 2);
    }
    
    public int CalculatePrice(int basePrice, int level)
    {
        return basePrice + (level * 10);
    }
}